"use client";

import { useState, useEffect } from "react";
import { fetchNewsList } from "@/lib/api";
import { getInterestKeywordsQuery } from "@/lib/interestKeywords";
import type { NewsListResponse } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import NewsCard from "@/components/news/NewsCard";

const categories = [
  { value: "all", label: "전체" },
  { value: "global", label: "글로벌" },
  { value: "domestic", label: "국내" },
];

export default function IssuesPage() {
  const [category, setCategory] = useState("all");
  const [data, setData] = useState<NewsListResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    const keywords = getInterestKeywordsQuery();
    fetchNewsList(category, 1, 10, keywords || undefined)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, [category]);

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">국내외 이슈</h1>

      {/* 카테고리 필터 */}
      <div className="flex gap-2">
        {categories.map((c) => (
          <button
            key={c.value}
            onClick={() => setCategory(c.value)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-colors ${
              category === c.value
                ? "bg-skyblue text-white"
                : "bg-white/5 text-gray-400 hover:text-white hover:bg-white/10"
            }`}
          >
            {c.label}
          </button>
        ))}
      </div>

      {loading && <LoadingSpinner />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <div className="space-y-3">
          {data.items.map((n) => (
            <NewsCard key={n.id} news={n} />
          ))}
        </div>
      )}
    </div>
  );
}
